#include<iostream>#include<vector>#include<algorithm>#define ll long longusing namespace std;int main(){    int t;    cin>>t;    while(t--){        ll n,c;        cin>>n>>c;        vector<ll>s(n);                for(int i=0;i<n;i++){            cin>>s[i];         }        int i=1;        int j= 1e9;        ll ans=0;        while(i<=j){            ll sum=0;            int mid= i + (j-i)/2;            for(int k=0;k<n;k++){                sum+=(s[k] + 2*mid)* (s[k] + 2*mid);                if(sum>c){                   break;                }            }            if(sum<=c){                ans=mid;                i= mid+1;            }            else{                j= mid-1;            }         }        cout<<ans<<"\n";    }}